# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

from flask import Flask, request, jsonify
from collections import Counter
import numpy as np
import pickle
from sklearn.ensemble import RandomForestClassifier
from sklearn.preprocessing import LabelEncoder
import os

app = Flask(__name__)

# Store annotations
annotations = {}
model = None
label_encoder = LabelEncoder()

@app.route('/label', methods=['POST'])
def add_annotation():
    data = request.get_json()
    image_id = data['image_id']
    label = data['label']
    annotator_id = data['annotator_id']
    
    if image_id not in annotations:
        annotations[image_id] = []
    
    annotations[image_id].append({
        'label': label,
        'annotator_id': annotator_id
    })
    
    return jsonify({'status': 'success'})

@app.route('/aggregate', methods=['GET'])
def aggregate_labels():
    aggregated = {}
    for image_id, labels in annotations.items():
        label_counts = Counter([l['label'] for l in labels])
        majority_label = label_counts.most_common(1)[0][0]
        aggregated[image_id] = majority_label
    
    return jsonify(aggregated)

@app.route('/train', methods=['POST'])
def train_model():
    global model, label_encoder
    
    # Prepare training data
    X = []
    y = []
    
    for image_id, labels in annotations.items():
        # Use majority vote for training
        label_counts = Counter([l['label'] for l in labels])
        majority_label = label_counts.most_common(1)[0][0]
        
        # For simplicity, assuming we have image features
        # In practice, you'd extract features from images
        X.append([hash(image_id) % 1000])  # Placeholder features
        y.append(majority_label)
    
    if len(X) == 0:
        return jsonify({'status': 'no data to train'})
    
    # Encode labels
    y_encoded = label_encoder.fit_transform(y)
    
    # Train model
    model = RandomForestClassifier(n_estimators=100)
    model.fit(X, y_encoded)
    
    return jsonify({'status': 'model trained'})

@app.route('/predict', methods=['POST'])
def predict():
    global model
    
    if model is None:
        return jsonify({'error': 'model not trained'})
    
    data = request.get_json()
    image_features = data['features']
    
    prediction = model.predict([image_features])
    predicted_label = label_encoder.inverse_transform(prediction)[0]
    
    return jsonify({'prediction': predicted_label})

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)